class Solution {
    public int[] intersect(int[] nums1, int[] nums2) {
        boolean[] used = new boolean[nums1.length];
        java.util.List<Integer> result = new java.util.ArrayList<>();

        for (int b : nums2) {
            for (int i = 0; i < nums1.length; i++) {
                if (!used[i] && nums1[i] == b) {
                    result.add(b);
                    used[i] = true;
                    break;
                }
            }
        }
        int[] output = new int[result.size()];
        for (int i = 0; i < output.length; i++) output[i] = result.get(i);
        return output;
    }
}

class Solution {
    public int[] intersect(int[] nums1, int[] nums2) {
        java.util.Map<Integer, Integer> counts = new java.util.HashMap<>();
        for (int num : nums1) {
            counts.put(num, counts.getOrDefault(num, 0) + 1);
        }

        java.util.List<Integer> result = new java.util.ArrayList<>();
        for (int num : nums2) {
            int count = counts.getOrDefault(num, 0);
            if (count > 0) {
                result.add(num);
                counts.put(num, count - 1);
            }
        }

        int[] output = new int[result.size()];
        for (int i = 0; i < output.length; i++) output[i] = result.get(i);
        return output;
    }
}

class Solution {
    public boolean isIsomorphic(String s, String t) {
        int[] sFirst = new int[128];
        int[] tFirst = new int[128];
        java.util.Arrays.fill(sFirst, -1);
        java.util.Arrays.fill(tFirst, -1);

        for (int i = 0; i < s.length(); i++) {
            char sc = s.charAt(i), tc = t.charAt(i);
            if (sFirst[sc] != tFirst[tc]) return false;
            sFirst[sc] = i;
            tFirst[tc] = i;
        }
        return true;
    }
}

class Solution {
    public boolean isIsomorphic(String s, String t) {
        java.util.Map<Character, Character> sToT = new java.util.HashMap<>();
        java.util.Map<Character, Character> tToS = new java.util.HashMap<>();

        for (int i = 0; i < s.length(); i++) {
            char sc = s.charAt(i), tc = t.charAt(i);

            if (sToT.containsKey(sc) && sToT.get(sc) != tc) return false;
            if (tToS.containsKey(tc) && tToS.get(tc) != sc) return false;

            sToT.put(sc, tc);
            tToS.put(tc, sc);
        }
        return true;
    }
}

class Solution {
    public boolean wordPattern(String pattern, String s) {
        String[] words = s.split(" ");
        if (pattern.length() != words.length) return false;

        java.util.Map<Character, Integer> charFirst = new java.util.HashMap<>();
        java.util.Map<String, Integer> wordFirst = new java.util.HashMap<>();

        for (int i = 0; i < pattern.length(); i++) {
            char c = pattern.charAt(i);
            String w = words[i];
            int cFirst = charFirst.getOrDefault(c, -1);
            int wFirstIdx = wordFirst.getOrDefault(w, -1);
            if (cFirst != wFirstIdx) return false;
            charFirst.put(c, i);
            wordFirst.put(w, i);
        }
        return true;
    }
}

class Solution {
    public boolean wordPattern(String pattern, String s) {
        String[] words = s.split(" ");
        if (pattern.length() != words.length) return false;

        java.util.Map<Character, String> charToWord = new java.util.HashMap<>();
        java.util.Map<String, Character> wordToChar = new java.util.HashMap<>();

        for (int i = 0; i < pattern.length(); i++) {
            char c = pattern.charAt(i);
            String w = words[i];

            if (charToWord.containsKey(c) && !charToWord.get(c).equals(w)) return false;
            if (wordToChar.containsKey(w) && wordToChar.get(w) != c) return false;

            charToWord.put(c, w);
            wordToChar.put(w, c);
        }
        return true;
    }
}

class Solution {
    public java.util.List<java.util.List<String>> groupAnagrams(String[] strs) {
        java.util.List<java.util.List<String>> groups = new java.util.ArrayList<>();
        for (String s : strs) {
            boolean placed = false;
            for (java.util.List<String> group : groups) {
                if (isAnagram(s, group.get(0))) {
                    group.add(s);
                    placed = true;
                    break;
                }
            }
            if (!placed) {
                java.util.List<String> newGroup = new java.util.ArrayList<>();
                newGroup.add(s);
                groups.add(newGroup);
            }
        }
        return groups;
    }

    private boolean isAnagram(String a, String b) {
        char[] ca = a.toCharArray(), cb = b.toCharArray();
        java.util.Arrays.sort(ca);
        java.util.Arrays.sort(cb);
        return java.util.Arrays.equals(ca, cb);
    }
}

class Solution {
    public java.util.List<java.util.List<String>> groupAnagrams(String[] strs) {
        java.util.Map<String, java.util.List<String>> groups = new java.util.HashMap<>();

        for (String s : strs) {
            char[] chars = s.toCharArray();
            java.util.Arrays.sort(chars);
            String key = new String(chars);

            groups.computeIfAbsent(key, k -> new java.util.ArrayList<>()).add(s);
        }
        return new java.util.ArrayList<>(groups.values());
    }
}

class Solution {
    public int longestConsecutive(int[] nums) {
        if (nums.length == 0) return 0;
        java.util.Arrays.sort(nums);

        int longest = 1, current = 1;
        for (int i = 1; i < nums.length; i++) {
            if (nums[i] == nums[i - 1]) continue; // skip duplicates
            if (nums[i] == nums[i - 1] + 1) {
                current++;
            } else {
                current = 1;
            }
            longest = Math.max(longest, current);
        }
        return longest;
    }
}

class Solution {
    public int longestConsecutive(int[] nums) {
        java.util.Set<Integer> numSet = new java.util.HashSet<>();
        for (int num : nums) numSet.add(num);

        int longest = 0;
        for (int num : numSet) {
            if (!numSet.contains(num - 1)) { // num is the START of a sequence
                int length = 1;
                while (numSet.contains(num + length)) {
                    length++;
                }
                longest = Math.max(longest, length);
            }
        }
        return longest;
    }
}

